request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?elem rdf:type ?type .
  FILTER(?type = vocab:tmt%20requirement)
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }
  OPTIONAL { ?elem rdf:type ?type . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?relType ?req ?reqName ?other ?otherName WHERE {
  {
    ?rel rdf:type ?relType .
    FILTER(?relType IN (vocab:satisfy, vocab:verify, vocab:allocate, vocab:dependency, vocab:dependency%20))
    ?rel ?p ?req .
  }
  UNION
  {
    ?req ?p ?other .
    FILTER(?p IN (vocab:client, vocab:supplier, vocab:Dependency_client, vocab:Dependency_supplier))
    BIND(vocab:dependency AS ?relType)
  }
  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?reqName . }
  OPTIONAL { ?other vocab:NamedElement_name ?otherName . }
}
LIMIT 25
